  ngAfterViewInit(): void {
    this.phone_counter=0;
    this.m = document.getElementById("myModal");
    this.m.style.display = 'none';
    this.user.get_Details(localStorage.getItem('u-id'), localStorage.getItem('user-type_user'), localStorage.getItem('remember_token')).subscribe(data => {
      // console.log(data)
      var obj = JSON.parse(data);
      // console.log(obj.message[0].name+" "+obj.message[0].email)
      this.p_name = obj.message[0].name;
      this.p_email = obj.message[0].email;
      this.p_phone = obj.message[0].phone;
      this.p_street = obj.message[0].street==undefined?'':obj.message[0].street;
      this.p_city = obj.message[0].city==undefined?'':obj.message[0].city;
      this.p_country = obj.message[0].country==undefined?'':obj.message[0].country;
      this.p_pin = obj.message[0].pincode==undefined?'':obj.message[0].pincode;
      this.p_state = obj.message[0].state==undefined?'':obj.message[0].state;
      this.email_verify=obj.message[0].email_verify;
      this.phone_verify=obj.message[0].phone_verify;
      this.profile = obj.message[0].image_url;
      this.profile_image = obj.message[0].profile_image;
       this.mode=(obj.message[0].student_academician == '' || obj.message[0].student_academician == null) ? '' : obj.message[0].student_academician ;
      if(this.mode=='S'){
        // console.log('s')
        this.Clg=true;
        this.Corporate=false;
        this.Advocate=false;
        $('#prac_area').attr('hidden',true);
        $('#com_name').attr('hidden',true);
        $('#colg').removeAttr('hidden');
        $('#prac_area').val('');
        $('#com_name').val('');
        $('#colg').val(obj.message[0].college_university);
      }
      else if(this.mode=='A'){
        // console.log('A')
        this.Clg=false;
        this.Corporate=false;
        this.Advocate=true;
        $('#colg').attr('hidden',true);
        $('#com_name').attr('hidden',true);
        $('#prac_area').removeAttr('hidden');
        $('#prac_area').val(obj.message[0].college_university);
        $('#com_name').val('');
        $('#colg').val('');
      }
      else if(this.mode=='C'){
        // console.log('C')
        this.Clg=false;
        this.Corporate=true;
        this.Advocate=false;
        $('#colg').attr('hidden',true);
        $('#prac_area').attr('hidden',true);
        $('#com_name').removeAttr('hidden');
        $('#prac_area').val('');
        $('#com_name').val(obj.message[0].college_university);
        $('#colg').val('');
      }
      else{}
      this.spin_show=false;
    })
    localStorage.setItem('address','/user/edit-user');
    $('#otpmodal').on('hidden.bs.modal',  ()=> {
      if(this.Mode=='M'){clearTimeout(this.getId);}
    })
  }
  modal_close_fun() {this.m.style.display = 'none';
    // this.router.navigate(['user/user_dashboard'])
  }
  modal_close_funtry() {this.m.style.display = 'none';}
  preventNonNumericalInput(e: any) {
    e = e || window.event;
      var charCode = (typeof e.which == "undefined") ? e.keyCode : e.which;
      var charStr = String.fromCharCode(charCode);
  
      if (!charStr.match(/^[0-9]+$/))
        e.preventDefault();
  }
  onChange(event: any) {

    this.file = event.target.files[0];
    //localStorage.setItem('profile',this.file);
    var ext = event.target.files[0].name.split('.').pop();
    // console.log(ext);
    if (ext == "jpeg" || ext == "jpg" || ext == 'png') {
      this.fval = event.target.files[0].name;
      const reader = new FileReader();
      reader.onload = () => {
        this.profile= reader.result as string;
        // this.img_src=reader.result as string;
      }
      reader.readAsDataURL(this.file);
    }
    else {
      this.m.style.display='block';
      this.modal_msg='Wrong format!!'
      this.fval = "";
    }
  }
  send_data(v1: any, v2: any, v3: any, v4: any, v5: any, v6: any, v7: any, v8: any) {
      var college_university=this.mode =='S' ? $('#colg').val() : (this.mode=='A' ? $('#prac_area').val():$('#com_name').val());
    //  console.log(college_university);
      this.spin_show = true;
      this.update=true;
    this.m.style.display = 'none';
    if (v1 != '' && v2 != '' && v3 != '' && v4 != '' && v5 != '' && v6 != '' && v7 != '' && v8 != '') {
    this.edit.edit_profile(localStorage.getItem('u-id'), v1, v2, v3, v4, v5, v6, v7, v8, localStorage.getItem('user-type_user'),this.mode,college_university,localStorage.getItem('remember_token'),this.file).subscribe(data => {
      var obj = JSON.parse(data);
      if (obj.success == 1) {
        this.spin_show = false;
        this.modal_msg='Your profile has been updated successfully!!';
        this.toastr.successToastr(this.modal_msg,'');
        this.user.get_Details(localStorage.getItem('u-id'), localStorage.getItem('user-type_user'), localStorage.getItem('remember_token')).subscribe(data => {
          var obj = JSON.parse(data);
          this.p_name = obj.message[0].name;
          this.p_email = obj.message[0].email;
          this.p_phone = obj.message[0].phone;
          this.p_street = obj.message[0].street==undefined?'':obj.message[0].street;
          this.p_city = obj.message[0].city==undefined?'':obj.message[0].city;
          this.p_country = obj.message[0].country==undefined?'':obj.message[0].country;
          this.p_pin = obj.message[0].pincode==undefined?'':obj.message[0].pincode;
          this.p_state = obj.message[0].state==undefined?'':obj.message[0].state;
          this.profile = obj.message[0].image_url;
          this.profile_image = obj.message[0].profile_image;
        })
      }
      else {
        // this.m.style.display = 'block';
        this.modal_msg='Error while updating.';
        this.toastr.errorToastr(this.modal_msg,'');
        this.spin_show = false;
      }
    });
  }
  else{
    this.spin_show = false;
    this.m.style.display='none';
    this.modal_msg='One or more fields may be empty.'
  }
  
  }
  hide_show(){
    this.show_form=!this.show_form
  }
