update_time(){

  var myTime =$('#counter_left').text();
  var ss = myTime.split(":");
  // console.log("SS:" +ss);
  var dt = new Date();
  dt.setHours(0);
  dt.setMinutes(ss[0]);
  dt.setSeconds(ss[1]);
  // console.log("DT:" +dt);
  var dt2 = new Date(dt.valueOf() - 1000);
  var temp = dt2.toTimeString().split(" ");
  var ts = temp[0].split(":");
 // console.log("dt2: "+ dt2+" temp: "+temp+" ts[1]: "+ts[1]+"  ts[2]: " +ts[2]);
  // console.log(typeof(ts[1]))
  $('#counter_left').text(ts[1]+":"+ts[2]);
 // console.log($('#counter_left').text())
  if(ts[1]=='00' && ts[2]=='00'){
  $('#counter_left').hide();
 // alert(temp[0].split(":")[0]+" "+temp[0].split(":")[1])
  $('#resendOtp').show();
  $('#counter_left').text('01:59');
  this.get_otp='';
  }
  else{
   this.getId=setTimeout(() => {
      this.update_time() 
    }, 1000);
  
  }
}
//For Resend OTP
Update(){
  this.check_response='';
  this.get_otp='';
  this.userOtp.getOtp(localStorage.getItem('u-id'), localStorage.getItem('user-type_user'), localStorage.getItem('remember_token'),this.otp_pn_em).subscribe(data=>{
    this.check_response=data;
    if(this.check_response.success==1){
      this.get_otp=this.check_response.otp;
      clearTimeout(this.getId)
      $('#counter_left').text('01:59');
      $('#counter_left').show();
      $('#resendOtp').hide();
      this.update_time();
    }
    else{
      this.toastr.errorToastr('Something went wrong! please try again later','');
    }
  })
}


