async modifyPdf(URL:any[]) {
  // this.pdfBytes='';
   this.loading=true;
  const pdfDoc = await PDFDocument.create()
  if(URL.length >= this.pdfmerge_maxLength){
    console.log("min:"+this.pdfmerge_minLength);
    console.log("max:"+this.pdfmerge_maxLength);
      for(let i=this.pdfmerge_minLength;i< this.pdfmerge_maxLength;i++){
        console.log("Index:"+i)
        var url=URL[i];
       const existingPdfBytes = await fetch(url).then(res => res.arrayBuffer())
       const firstDonorPdfDoc = await PDFDocument.load(existingPdfBytes);
       const [firstDonorPage] = await pdfDoc.copyPages(firstDonorPdfDoc, [0])
       pdfDoc.addPage(firstDonorPage);
      }
  this.loading=false;
  }
  else{
     this.pdfmerge_maxLength=this.Full_Book.length;
    for(let i=0;i< URL.length;i++){
      var url=URL[i];
     const existingPdfBytes = await fetch(url).then(res => res.arrayBuffer())
     const firstDonorPdfDoc = await PDFDocument.load(existingPdfBytes);
     const [firstDonorPage] = await pdfDoc.copyPages(firstDonorPdfDoc, [0])
     pdfDoc.addPage(firstDonorPage);
   }
   this.pdfBytes = await pdfDoc.save()

  this.loading=false;

  }
  this.pdfBytes = await pdfDoc.save()
  this.open_pg=this.page_open==1 ? 50 : 1;
  this.page_open=this.open_pg;
}
