changePage(event:any){
  this.page_open='';
  if(event==50){
      this.page_open=event;
     this.pdfmerge_minLength=this.pdfmerge_maxLength-1;
     this.pdfmerge_maxLength=this.pdfmerge_minLength+50;
     if(this.pdfmerge_maxLength>this.pdf_urls.length){
       this.pdfmerge_maxLength=this.pdf_urls.length;
       this.modifyPdf(this.pdf_urls);     
      }
      else if(this.pdfmerge_maxLength < this.pdf_urls.length){
       this.modifyPdf(this.pdf_urls);     
      }
      else{

      }
  }
  else if(event==1){
    console.log('Min:'+this.pdfmerge_minLength+'- Max:'+this.pdfmerge_maxLength)
     if(this.pdfmerge_minLength>0){
       this.page_open=1;
       this.pdfmerge_maxLength=this.pdfmerge_minLength+1;
       this.pdfmerge_minLength=(this.pdfmerge_maxLength-50);
       if(this.pdfmerge_minLength < 0){
        this.pdfmerge_maxLength=50;
        this.pdfmerge_minLength=0;
       }
         this.modifyPdf(this.pdf_urls)
     }

  }
}


async modifyPdf(URL:any[]) {
  // this.pdfBytes='';
    this.load=true;
  const pdfDoc = await PDFDocument.create()
  if(URL.length >= this.pdfmerge_maxLength){
    console.log("min:"+this.pdfmerge_minLength);
    console.log("max:"+this.pdfmerge_maxLength);
      for(let i=this.pdfmerge_minLength;i< this.pdfmerge_maxLength;i++){
        console.log("Index:"+i)
        var url=URL[i];
       const existingPdfBytes = await fetch(url).then(res => res.arrayBuffer())
       const firstDonorPdfDoc = await PDFDocument.load(existingPdfBytes);
       const [firstDonorPage] = await pdfDoc.copyPages(firstDonorPdfDoc, [0])
       pdfDoc.addPage(firstDonorPage);
      }
   this.load=false;
  }
  else{
     this.pdfmerge_maxLength=this.pdf_urls.length;
    for(let i=0;i< URL.length;i++){
      var url=URL[i];
     const existingPdfBytes = await fetch(url).then(res => res.arrayBuffer())
     const firstDonorPdfDoc = await PDFDocument.load(existingPdfBytes);
     const [firstDonorPage] = await pdfDoc.copyPages(firstDonorPdfDoc, [0])
     pdfDoc.addPage(firstDonorPage);
   }
   this.pdfBytes = await pdfDoc.save()

   this.load=false;

  }
  this.pdfBytes = await pdfDoc.save()
  this.open_pg=this.page_open==1 ? 50 : 1;
  this.page_open=this.open_pg;
}
